     1→package openai
     2→
     3→import (
     4→	"bytes"
     5→	"context"
     6→	"encoding/json"
     7→	"fmt"
     8→	"io"
     9→	"iter"
    10→	"net/http"
    11→
    12→	"google.golang.org/adk/model"
    13→	"google.golang.org/genai"
    14→)
    15→
    16→const defaultBaseURL = "https://api.openai.com/v1"
    17→
    18→// Config holds connection parameters for an OpenAI-compatible API.
    19→type Config struct {
    20→	APIKey  string
    21→	BaseURL string // defaults to https://api.openai.com/v1
    22→}
    23→
    24→// openaiModel implements model.LLM for OpenAI-compatible chat completion APIs.
    25→type openaiModel struct {
    26→	name    string
    27→	apiKey  string
    28→	baseURL string
    29→	client  *http.Client
    30→}
    31→
    32→// NewModel creates an OpenAI-backed model.LLM.
    33→func NewModel(_ context.Context, modelName string, cfg Config) (model.LLM, error) {
    34→	if cfg.APIKey == "" {
    35→		return nil, fmt.Errorf("openai: API key is required")
    36→	}
    37→	baseURL := cfg.BaseURL
    38→	if baseURL == "" {
    39→		baseURL = defaultBaseURL
    40→	}
    41→	return &openaiModel{
    42→		name:    modelName,
    43→		apiKey:  cfg.APIKey,
    44→		baseURL: baseURL,
    45→		client:  &http.Client{},
    46→	}, nil
    47→}
    48→
    49→func (m *openaiModel) Name() string { return m.name }
    50→
    51→// GenerateContent converts the ADK request to an OpenAI chat completion request,
    52→// calls the API, and converts the response back to an LLMResponse.
    53→// Streaming is not implemented; the iterator always yields a single response.
    54→func (m *openaiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, _ bool) iter.Seq2[*model.LLMResponse, error] {
    55→	return func(yield func(*model.LLMResponse, error) bool) {
    56→		resp, err := m.doRequest(ctx, req)
    57→		if err != nil {
    58→			yield(nil, err)
    59→			return
    60→		}
    61→		yield(resp, nil)
    62→	}
    63→}
    64→
    65→// Close is a no-op; the HTTP client has no persistent state.
    66→func (m *openaiModel) Close() {}
    67→
    68→// --- OpenAI API types ---
    69→
    70→type chatRequest struct {
    71→	Model       string        `json:"model"`
    72→	Messages    []chatMessage `json:"messages"`
    73→	Tools       []chatTool    `json:"tools,omitempty"`
    74→	Temperature *float32      `json:"temperature,omitempty"`
    75→	TopP        *float32      `json:"top_p,omitempty"`
    76→	MaxTokens   int32         `json:"max_tokens,omitempty"`
    77→	Stop        []string      `json:"stop,omitempty"`
    78→	Stream      bool          `json:"stream"`
    79→}
    80→
    81→type chatMessage struct {
    82→	Role       string     `json:"role"`
    83→	Content    string     `json:"content,omitempty"`
    84→	ToolCalls  []toolCall `json:"tool_calls,omitempty"`
    85→	ToolCallID string     `json:"tool_call_id,omitempty"`
    86→}
    87→
    88→type toolCall struct {
    89→	ID       string       `json:"id"`
    90→	Type     string       `json:"type"`
    91→	Function functionCall `json:"function"`
    92→}
    93→
    94→type functionCall struct {
    95→	Name      string `json:"name"`
    96→	Arguments string `json:"arguments"`
    97→}
    98→
    99→type chatTool struct {
   100→	Type     string       `json:"type"`
   101→	Function chatFunction `json:"function"`
   102→}
   103→
   104→type chatFunction struct {
   105→	Name        string `json:"name"`
   106→	Description string `json:"description,omitempty"`
   107→	Parameters  any    `json:"parameters,omitempty"`
   108→}
   109→
   110→type chatResponse struct {
   111→	Choices []chatChoice `json:"choices"`
   112→	Usage   *chatUsage   `json:"usage,omitempty"`
   113→	Error   *apiError    `json:"error,omitempty"`
   114→}
   115→
   116→type chatChoice struct {
   117→	Message      chatMessage `json:"message"`
   118→	FinishReason string      `json:"finish_reason"`
   119→}
   120→
   121→type chatUsage struct {
   122→	PromptTokens     int32 `json:"prompt_tokens"`
   123→	CompletionTokens int32 `json:"completion_tokens"`
   124→	TotalTokens      int32 `json:"total_tokens"`
   125→}
   126→
   127→type apiError struct {
   128→	Message string `json:"message"`
   129→	Type    string `json:"type"`
   130→	Code    string `json:"code"`
   131→}
   132→
   133→// --- request/response conversion ---
   134→
   135→func (m *openaiModel) doRequest(ctx context.Context, req *model.LLMRequest) (*model.LLMResponse, error) {
   136→	msgs := convertContents(req)
   137→	tools := convertTools(req)
   138→
   139→	chatReq := chatRequest{
   140→		Model:    m.name,
   141→		Messages: msgs,
   142→		Tools:    tools,
   143→		Stream:   false,
   144→	}
   145→
   146→	if req.Config != nil {
   147→		chatReq.Temperature = req.Config.Temperature
   148→		chatReq.TopP = req.Config.TopP
   149→		if req.Config.MaxOutputTokens > 0 {
   150→			chatReq.MaxTokens = req.Config.MaxOutputTokens
   151→		}
   152→		if len(req.Config.StopSequences) > 0 {
   153→			chatReq.Stop = req.Config.StopSequences
   154→		}
   155→	}
   156→
   157→	body, err := json.Marshal(chatReq)
   158→	if err != nil {
   159→		return nil, fmt.Errorf("openai: marshal request: %w", err)
   160→	}
   161→
   162→	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, m.baseURL+"/chat/completions", bytes.NewReader(body))
   163→	if err != nil {
   164→		return nil, fmt.Errorf("openai: create http request: %w", err)
   165→	}
   166→	httpReq.Header.Set("Content-Type", "application/json")
   167→	httpReq.Header.Set("Authorization", "Bearer "+m.apiKey)
   168→
   169→	httpResp, err := m.client.Do(httpReq)
   170→	if err != nil {
   171→		return nil, fmt.Errorf("openai: http request: %w", err)
   172→	}
   173→	defer httpResp.Body.Close()
   174→
   175→	respBody, err := io.ReadAll(httpResp.Body)
   176→	if err != nil {
   177→		return nil, fmt.Errorf("openai: read response: %w", err)
   178→	}
   179→
   180→	if httpResp.StatusCode != http.StatusOK {
   181→		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   182→	}
   183→
   184→	var chatResp chatResponse
   185→	if err := json.Unmarshal(respBody, &chatResp); err != nil {
   186→		return nil, fmt.Errorf("openai: unmarshal response: %w", err)
   187→	}
   188→
   189→	if chatResp.Error != nil {
   190→		return nil, fmt.Errorf("openai: API error: %s (type=%s, code=%s)",
   191→			chatResp.Error.Message, chatResp.Error.Type, chatResp.Error.Code)
   192→	}
   193→
   194→	return convertResponse(&chatResp), nil
   195→}
   196→
   197→// convertContents transforms ADK genai.Content messages into OpenAI chat messages.
   198→func convertContents(req *model.LLMRequest) []chatMessage {
   199→	var msgs []chatMessage
   200→
   201→	// System instruction.
   202→	if req.Config != nil && req.Config.SystemInstruction != nil {
   203→		var text string
   204→		for _, p := range req.Config.SystemInstruction.Parts {
   205→			if p.Text != "" {
   206→				text += p.Text
   207→			}
   208→		}
   209→		if text != "" {
   210→			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   211→		}
   212→	}
   213→
   214→	// Conversation contents.
   215→	for _, c := range req.Contents {
   216→		role := mapRole(c.Role)
   217→
   218→		// Check each part: could be text, function_call, or function_response.
   219→		for _, p := range c.Parts {
   220→			switch {
   221→			case p.FunctionCall != nil:
   222→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   223→				msgs = append(msgs, chatMessage{
   224→					Role: "assistant",
   225→					ToolCalls: []toolCall{{
   226→						ID:   p.FunctionCall.ID,
   227→						Type: "function",
   228→						Function: functionCall{
   229→							Name:      p.FunctionCall.Name,
   230→							Arguments: string(argsJSON),
   231→						},
   232→					}},
   233→				})
   234→			case p.FunctionResponse != nil:
   235→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   236→				msgs = append(msgs, chatMessage{
   237→					Role:       "tool",
   238→					Content:    string(respJSON),
   239→					ToolCallID: p.FunctionResponse.ID,
   240→				})
   241→			case p.Text != "":
   242→				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   243→			}
   244→		}
   245→	}
   246→
   247→	// Merge consecutive assistant messages with tool_calls.
   248→	msgs = mergeAssistantToolCalls(msgs)
   249→
   250→	return msgs
   251→}
   252→
   253→// mergeAssistantToolCalls combines adjacent assistant messages that each have
   254→// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   255→// one message rather than separate messages.
   256→func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   257→	if len(msgs) == 0 {
   258→		return msgs
   259→	}
   260→	var merged []chatMessage
   261→	for _, msg := range msgs {
   262→		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   263→			prev := &merged[len(merged)-1]
   264→			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   265→				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
   266→				continue
   267→			}
   268→		}
   269→		merged = append(merged, msg)
   270→	}
   271→	return merged
   272→}
   273→
   274→// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   275→func convertTools(req *model.LLMRequest) []chatTool {
   276→	if req.Config == nil || len(req.Config.Tools) == 0 {
   277→		return nil
   278→	}
   279→
   280→	var tools []chatTool
   281→	for _, t := range req.Config.Tools {
   282→		for _, fd := range t.FunctionDeclarations {
   283→			ct := chatTool{
   284→				Type: "function",
   285→				Function: chatFunction{
   286→					Name:        fd.Name,
   287→					Description: fd.Description,
   288→				},
   289→			}
   290→			if fd.Parameters != nil {
   291→				ct.Function.Parameters = schemaToMap(fd.Parameters)
   292→			}
   293→			tools = append(tools, ct)
   294→		}
   295→	}
   296→	return tools
   297→}
   298→
   299→// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   300→// the OpenAI function parameters format (JSON Schema).
   301→func schemaToMap(s *genai.Schema) map[string]any {
   302→	m := map[string]any{}
   303→	if s.Type != "" {
   304→		m["type"] = string(s.Type)
   305→	}
   306→	if s.Description != "" {
   307→		m["description"] = s.Description
   308→	}
   309→	if len(s.Enum) > 0 {
   310→		m["enum"] = s.Enum
   311→	}
   312→	if s.Items != nil {
   313→		m["items"] = schemaToMap(s.Items)
   314→	}
   315→	if len(s.Properties) > 0 {
   316→		props := map[string]any{}
   317→		for k, v := range s.Properties {
   318→			props[k] = schemaToMap(v)
   319→		}
   320→		m["properties"] = props
   321→	}
   322→	if len(s.Required) > 0 {
   323→		m["required"] = s.Required
   324→	}
   325→	return m
   326→}
   327→
   328→// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   329→func convertResponse(resp *chatResponse) *model.LLMResponse {
   330→	llmResp := &model.LLMResponse{
   331→		TurnComplete: true,
   332→	}
   333→
   334→	if len(resp.Choices) == 0 {
   335→		llmResp.Content = genai.NewContentFromText("", "model")
   336→		return llmResp
   337→	}
   338→
   339→	choice := resp.Choices[0]
   340→	llmResp.FinishReason = mapFinishReason(choice.FinishReason)
   341→
   342→	content := &genai.Content{Role: "model"}
   343→
   344→	// Text content.
   345→	if choice.Message.Content != "" {
   346→		content.Parts = append(content.Parts, &genai.Part{Text: choice.Message.Content})
   347→	}
   348→
   349→	// Tool calls.
   350→	for _, tc := range choice.Message.ToolCalls {
   351→		var args map[string]any
   352→		if tc.Function.Arguments != "" {
   353→			_ = json.Unmarshal([]byte(tc.Function.Arguments), &args)
   354→		}
   355→		content.Parts = append(content.Parts, &genai.Part{
   356→			FunctionCall: &genai.FunctionCall{
   357→				ID:   tc.ID,
   358→				Name: tc.Function.Name,
   359→				Args: args,
   360→			},
   361→		})
   362→	}
   363→
   364→	llmResp.Content = content
   365→
   366→	if resp.Usage != nil {
   367→		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   368→			PromptTokenCount:     resp.Usage.PromptTokens,
   369→			CandidatesTokenCount: resp.Usage.CompletionTokens,
   370→			TotalTokenCount:      resp.Usage.TotalTokens,
   371→		}
   372→	}
   373→
   374→	return llmResp
   375→}
   376→
