   197→// convertContents transforms ADK genai.Content messages into OpenAI chat messages.
   198→func convertContents(req *model.LLMRequest) []chatMessage {
   199→	var msgs []chatMessage
   200→
   201→	// System instruction.
   202→	if req.Config != nil && req.Config.SystemInstruction != nil {
   203→		var text string
   204→		for _, p := range req.Config.SystemInstruction.Parts {
   205→			if p.Text != "" {
   206→				text += p.Text
   207→			}
   208→		}
   209→		if text != "" {
   210→			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   211→		}
   212→	}
   213→
   214→	// Conversation contents.
   215→	for _, c := range req.Contents {
   216→		role := mapRole(c.Role)
   217→
   218→		// Check each part: could be text, function_call, or function_response.
   219→		for _, p := range c.Parts {
   220→			switch {
   221→			case p.FunctionCall != nil:
   222→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   223→				msgs = append(msgs, chatMessage{
   224→					Role: "assistant",
   225→					ToolCalls: []toolCall{{
   226→						ID:   p.FunctionCall.ID,
   227→						Type: "function",
   228→						Function: functionCall{
   229→							Name:      p.FunctionCall.Name,
   230→							Arguments: string(argsJSON),
   231→						},
   232→					}},
   233→				})
   234→			case p.FunctionResponse != nil:
   235→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   236→				msgs = append(msgs, chatMessage{
   237→					Role:       "tool",
   238→					Content:    string(respJSON),
   239→					ToolCallID: p.FunctionResponse.ID,
   240→				})
   241→			case p.Text != "":
   242→				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   243→			}
   244→		}
   245→	}
   246→
   247→	// Merge consecutive assistant messages with tool_calls.
   248→	msgs = mergeAssistantToolCalls(msgs)
   249→
   250→	return msgs
   251→}
   252→
   253→// mergeAssistantToolCalls combines adjacent assistant messages that each have
   254→// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   255→// one message rather than separate messages.
   256→func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   257→	if len(msgs) == 0 {
   258→		return msgs
   259→	}
   260→	var merged []chatMessage
   261→	for _, msg := range msgs {
   262→		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   263→			prev := &merged[len(merged)-1]
   264→			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   265→				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
   266→				continue
   267→			}
   268→		}
   269→		merged = append(merged, msg)
   270→	}
   271→	return merged
   272→}
   273→
   274→// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   275→func convertTools(req *model.LLMRequest) []chatTool {
   276→	if req.Config == nil || len(req.Config.Tools) == 0 {
   277→		return nil
   278→	}
   279→
   280→	var tools []chatTool
   281→	for _, t := range req.Config.Tools {
   282→		for _, fd := range t.FunctionDeclarations {
   283→			ct := chatTool{
   284→				Type: "function",
   285→				Function: chatFunction{
   286→					Name:        fd.Name,
   287→					Description: fd.Description,
   288→				},
   289→			}
   290→			if fd.Parameters != nil {
   291→				ct.Function.Parameters = schemaToMap(fd.Parameters)
   292→			}
   293→			tools = append(tools, ct)
   294→		}
   295→	}
   296→	return tools
   297→}
   298→
   299→// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   300→// the OpenAI function parameters format (JSON Schema).
   301→func schemaToMap(s *genai.Schema) map[string]any {
   302→	m := map[string]any{}
   303→	if s.Type != "" {
   304→		m["type"] = string(s.Type)
   305→	}
   306→	if s.Description != "" {
   307→		m["description"] = s.Description
   308→	}
   309→	if len(s.Enum) > 0 {
   310→		m["enum"] = s.Enum
   311→	}
   312→	if s.Items != nil {
   313→		m["items"] = schemaToMap(s.Items)
   314→	}
   315→	if len(s.Properties) > 0 {
   316→		props := map[string]any{}
   317→		for k, v := range s.Properties {
   318→			props[k] = schemaToMap(v)
   319→		}
   320→		m["properties"] = props
   321→	}
   322→	if len(s.Required) > 0 {
   323→		m["required"] = s.Required
   324→	}
   325→	return m
   326→}
   327→
   328→// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   329→func convertResponse(resp *chatResponse) *model.LLMResponse {
   330→	llmResp := &model.LLMResponse{
   331→		TurnComplete: true,
   332→	}
   333→
   334→	if len(resp.Choices) == 0 {
   335→		llmResp.Content = genai.NewContentFromText("", "model")
   336→		return llmResp
   337→	}
   338→
   339→	choice := resp.Choices[0]
   340→	llmResp.FinishReason = mapFinishReason(choice.FinishReason)
   341→
   342→	content := &genai.Content{Role: "model"}
   343→
   344→	// Text content.
   345→	if choice.Message.Content != "" {
   346→		content.Parts = append(content.Parts, &genai.Part{Text: choice.Message.Content})
   347→	}
   348→
   349→	// Tool calls.
   350→	for _, tc := range choice.Message.ToolCalls {
   351→		var args map[string]any
   352→		if tc.Function.Arguments != "" {
   353→			_ = json.Unmarshal([]byte(tc.Function.Arguments), &args)
   354→		}
   355→		content.Parts = append(content.Parts, &genai.Part{
   356→			FunctionCall: &genai.FunctionCall{
   357→				ID:   tc.ID,
   358→				Name: tc.Function.Name,
   359→				Args: args,
   360→			},
   361→		})
   362→	}
   363→
   364→	llmResp.Content = content
   365→
   366→	if resp.Usage != nil {
   367→		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   368→			PromptTokenCount:     resp.Usage.PromptTokens,
   369→			CandidatesTokenCount: resp.Usage.CompletionTokens,
   370→			TotalTokenCount:      resp.Usage.TotalTokens,
   371→		}
   372→	}
   373→
   374→	return llmResp
   375→}
   376→
   377→func mapRole(role string) string {
   378→	switch role {
   379→	case "model":
   380→		return "assistant"
   381→	default:
   382→		return role
   383→	}
   384→}
   385→
   386→func mapFinishReason(reason string) genai.FinishReason {
   387→	switch reason {
   388→	case "stop":
   389→		return genai.FinishReasonStop
   390→	case "length":
   391→		return genai.FinishReasonMaxTokens
   392→	case "tool_calls":
   393→		return genai.FinishReasonStop
   394→	case "content_filter":
   395→		return genai.FinishReasonSafety
   396→	default:
   397→		return genai.FinishReasonOther
   398→	}
   399→}
