    85→// toolFactory holds the store reference and project ID scoped to a single
    86→// agent run. Tools created from this factory are bound to a specific project.
    87→type toolFactory struct {
    88→	store     AgentDataStore
    89→	projectID string
    90→}
    91→
    92→// NewTools creates the ADK function tools for agent research, scoped to a
    93→// specific project. The returned tools use the provided store to query
    94→// releases and context sources belonging to projectID.
    95→func NewTools(store AgentDataStore, projectID string) ([]tool.Tool, error) {
    96→	f := &toolFactory{store: store, projectID: projectID}
    97→
    98→	getReleases, err := functiontool.New(functiontool.Config{
    99→		Name:        "get_releases",
   100→		Description: "Fetch recent releases for the current project. Returns a paginated list of releases with version, raw data, and timestamps. Use this to understand what new versions have been published.",
   101→	}, f.getReleases)
   102→	if err != nil {
   103→		return nil, fmt.Errorf("create get_releases tool: %w", err)
   104→	}
   105→
   106→	getReleaseDetail, err := functiontool.New(functiontool.Config{
   107→		Name:        "get_release_detail",
   108→		Description: "Get detailed information for a specific release by its ID. Returns the full raw data payload from the upstream provider. Use this to inspect changelogs, commit lists, or other release metadata.",
   109→	}, f.getReleaseDetail)
   110→	if err != nil {
   111→		return nil, fmt.Errorf("create get_release_detail tool: %w", err)
   112→	}
   113→
   114→	listContextSources, err := functiontool.New(functiontool.Config{
   115→		Name:        "list_context_sources",
   116→		Description: "List the context sources configured for this project. Context sources are references to runbooks, documentation, monitoring dashboards, and other background materials that help you produce richer analysis.",
   117→	}, f.listContextSources)
   118→	if err != nil {
   119→		return nil, fmt.Errorf("create list_context_sources tool: %w", err)
   120→	}
   121→
   122→	return []tool.Tool{getReleases, getReleaseDetail, listContextSources}, nil
   123→}
   124→
   125→// getReleases is the handler for the get_releases tool.
   126→func (f *toolFactory) getReleases(ctx tool.Context, input GetReleasesInput) (GetReleasesOutput, error) {
   127→	page := input.Page
   128→	if page < 1 {
   129→		page = 1
   130→	}
   131→	perPage := input.PerPage
   132→	if perPage < 1 || perPage > 50 {
   133→		perPage = 20
   134→	}
   135→
   136→	releases, total, err := f.store.ListReleasesByProject(ctx, f.projectID, page, perPage)
   137→	if err != nil {
   138→		return GetReleasesOutput{}, fmt.Errorf("list releases: %w", err)
   139→	}
   140→
   141→	items := make([]ReleaseItem, 0, len(releases))
   142→	for _, r := range releases {
   143→		item := ReleaseItem{
   144→			ID:        r.ID,
   145→			SourceID:  r.SourceID,
   146→			Version:   r.Version,
   147→			RawData:   r.RawData,
   148→			CreatedAt: r.CreatedAt.Format("2006-01-02T15:04:05Z"),
   149→		}
   150→		if r.ReleasedAt != nil {
   151→			item.ReleasedAt = r.ReleasedAt.Format("2006-01-02T15:04:05Z")
   152→		}
   153→		items = append(items, item)
   154→	}
   155→
   156→	return GetReleasesOutput{
   157→		Releases: items,
   158→		Total:    total,
   159→		Page:     page,
   160→		PerPage:  perPage,
   161→	}, nil
   162→}
   163→
   164→// getReleaseDetail is the handler for the get_release_detail tool.
   165→func (f *toolFactory) getReleaseDetail(ctx tool.Context, input GetReleaseDetailInput) (GetReleaseDetailOutput, error) {
   166→	if input.ReleaseID == "" {
   167→		return GetReleaseDetailOutput{}, fmt.Errorf("release_id is required")
   168→	}
   169→
   170→	release, err := f.store.GetRelease(ctx, input.ReleaseID)
   171→	if err != nil {
   172→		return GetReleaseDetailOutput{}, fmt.Errorf("get release: %w", err)
   173→	}
   174→
   175→	out := GetReleaseDetailOutput{
   176→		ID:        release.ID,
   177→		SourceID:  release.SourceID,
   178→		Version:   release.Version,
   179→		RawData:   release.RawData,
   180→		CreatedAt: release.CreatedAt.Format("2006-01-02T15:04:05Z"),
   181→	}
   182→	if release.ReleasedAt != nil {
   183→		out.ReleasedAt = release.ReleasedAt.Format("2006-01-02T15:04:05Z")
   184→	}
   185→
   186→	return out, nil
   187→}
   188→
   189→// listContextSources is the handler for the list_context_sources tool.
   190→func (f *toolFactory) listContextSources(ctx tool.Context, input ListContextSourcesInput) (ListContextSourcesOutput, error) {
   191→	page := input.Page
   192→	if page < 1 {
   193→		page = 1
   194→	}
   195→	perPage := input.PerPage
   196→	if perPage < 1 || perPage > 50 {
   197→		perPage = 20
   198→	}
   199→
   200→	sources, total, err := f.store.ListContextSources(ctx, f.projectID, page, perPage)
   201→	if err != nil {
   202→		return ListContextSourcesOutput{}, fmt.Errorf("list context sources: %w", err)
   203→	}
   204→
   205→	items := make([]ContextSourceItem, 0, len(sources))
   206→	for _, s := range sources {
   207→		items = append(items, ContextSourceItem{
   208→			ID:     s.ID,
   209→			Type:   s.Type,
   210→			Name:   s.Name,
   211→			Config: s.Config,
   212→		})
   213→	}
   214→
   215→	return ListContextSourcesOutput{
   216→		Sources: items,
   217→		Total:   total,
   218→		Page:    page,
   219→		PerPage: perPage,
   220→	}, nil
   221→}
