   588→func (s *PgStore) TriggerAgentRun(ctx context.Context, projectID, trigger string) (*models.AgentRun, error) {
   589→	var run models.AgentRun
   590→	err := s.pool.QueryRow(ctx,
   591→		`INSERT INTO agent_runs (project_id, trigger, status)
   592→		 VALUES ($1, $2, 'pending')
   593→		 RETURNING id, project_id, trigger, status, created_at`,
   594→		projectID, trigger,
   595→	).Scan(&run.ID, &run.ProjectID, &run.Trigger, &run.Status, &run.CreatedAt)
   596→	if err != nil {
   597→		return nil, fmt.Errorf("insert agent run: %w", err)
   598→	}
   599→
   600→	// Enqueue a River job to process the agent run, if river client is available.
   601→	if s.river != nil {
   602→		_, err = s.river.Insert(ctx, queue.AgentJobArgs{
   603→			AgentRunID: run.ID,
   604→			ProjectID:  projectID,
   605→		}, nil)
   606→		if err != nil {
   607→			return nil, fmt.Errorf("enqueue agent job: %w", err)
   608→		}
   609→	}
   610→
   611→	return &run, nil
   612→}
