   702→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   703→// This follows the transactional outbox pattern for zero-loss guarantee.
   704→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger string) error {
   705→	tx, err := s.pool.Begin(ctx)
   706→	if err != nil {
   707→		return fmt.Errorf("begin tx: %w", err)
   708→	}
   709→	defer tx.Rollback(ctx)
   710→
   711→	var runID string
   712→	err = tx.QueryRow(ctx,
   713→		`INSERT INTO agent_runs (project_id, trigger, status)
   714→		 VALUES ($1, $2, 'pending')
   715→		 RETURNING id`, projectID, trigger,
   716→	).Scan(&runID)
   717→	if err != nil {
   718→		return fmt.Errorf("insert agent run: %w", err)
   719→	}
   720→
   721→	if s.river != nil {
   722→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   723→			AgentRunID: runID,
   724→			ProjectID:  projectID,
   725→		}, nil)
   726→		if err != nil {
   727→			return fmt.Errorf("enqueue agent job: %w", err)
   728→		}
   729→	}
   730→
   731→	return tx.Commit(ctx)
   732→}
