   736→// UpdateAgentRunStatus sets the status of an agent run and updates the
   737→// started_at timestamp when transitioning to "running".
   738→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   739→	var query string
   740→	switch status {
   741→	case "running":
   742→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   743→	case "completed":
   744→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   745→	default:
   746→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   747→	}
   748→	tag, err := s.pool.Exec(ctx, query, status, id)
   749→	if err != nil {
   750→		return fmt.Errorf("update agent run status: %w", err)
   751→	}
   752→	if tag.RowsAffected() == 0 {
   753→		return fmt.Errorf("agent run not found: %s", id)
   754→	}
   755→	return nil
   756→}
