   758→// CreateSemanticRelease inserts a semantic release and its source release links
   759→// in a single transaction. The sr.ID field is populated on success.
   760→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   761→	tx, err := s.pool.Begin(ctx)
   762→	if err != nil {
