   767→	err = tx.QueryRow(ctx,
   768→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   769→		 VALUES ($1, $2, $3, $4, $5)
   770→		 RETURNING id, created_at`,
   771→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   772→	).Scan(&sr.ID, &sr.CreatedAt)
   773→	if err != nil {
