    23→
    24→// openaiModel implements model.LLM for OpenAI-compatible chat completion APIs.
    25→type openaiModel struct {
    26→	name    string
    27→	apiKey  string
    28→	baseURL string
    29→	client  *http.Client
    30→}
    31→
    32→// NewModel creates an OpenAI-backed model.LLM.
    33→func NewModel(_ context.Context, modelName string, cfg Config) (model.LLM, error) {
    34→	if cfg.APIKey == "" {
    35→		return nil, fmt.Errorf("openai: API key is required")
    36→	}
    37→	baseURL := cfg.BaseURL
    38→	if baseURL == "" {
    39→		baseURL = defaultBaseURL
    40→	}
    41→	return &openaiModel{
    42→		name:    modelName,
    43→		apiKey:  cfg.APIKey,
    44→		baseURL: baseURL,
    45→		client:  &http.Client{},
    46→	}, nil
    47→}
