    51→// GenerateContent converts the ADK request to an OpenAI chat completion request,
    52→// calls the API, and converts the response back to an LLMResponse.
    53→// Streaming is not implemented; the iterator always yields a single response.
    54→func (m *openaiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, _ bool) iter.Seq2[*model.LLMResponse, error] {
    55→	return func(yield func(*model.LLMResponse, error) bool) {
    56→		resp, err := m.doRequest(ctx, req)
    57→		if err != nil {
    58→			yield(nil, err)
    59→			return
    60→		}
    61→		yield(resp, nil)
    62→	}
    63→}
    64→
    65→// Close is a no-op; the HTTP client has no persistent state.
    66→func (m *openaiModel) Close() {}
